import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'
import tailwindcss from '@tailwindcss/vite'

export default defineConfig({
  plugins: [react(), tailwindcss()],
  test: {
    globals: true,
    environment: 'jsdom',
    setupFiles: './src/test/setup.ts',
    include: ['src/**/*.{test,spec}.{ts,tsx}'],
  },
})

import '@testing-library/jest-dom/vitest'

const storage = new Map<string, string>()

const localStorageMock: Storage = {
  getItem: (key) => storage.get(key) ?? null,
  setItem: (key, value) => {
    storage.set(key, value)
  },
  removeItem: (key) => {
    storage.delete(key)
  },
  clear: () => {
    storage.clear()
  },
  get length() {
    return storage.size
  },
  key: (index) => Array.from(storage.keys())[index] ?? null,
}

Object.defineProperty(globalThis, 'localStorage', { value: localStorageMock, writable: true })

beforeEach(() => {
  storage.clear()
})

import type { LearningPlan } from '../types'

export function createMockPlan(overrides: Partial<LearningPlan> = {}): LearningPlan {
  return {
    id: overrides.id ?? 'plan-1',
    title: overrides.title ?? 'React 基础',
    startDate: overrides.startDate ?? '2026-06-01',
    days: overrides.days ?? 2,
    dailyHours: overrides.dailyHours ?? 2,
    notes: overrides.notes,
    createdAt: overrides.createdAt ?? '2026-06-01T08:00:00.000Z',
    dailyPlans: overrides.dailyPlans ?? [
      {
        date: '2026-06-01',
        goal: '第 1 天：React 基础 — 入门阶段学习',
        tasks: [
          {
            id: 't1',
            title: 'React 基础概念',
            description: '学习核心概念',
            estimatedHours: 1.2,
            completed: false,
            practiceSuggestion: '整理笔记',
          },
          {
            id: 't2',
            title: '动手练习',
            description: '完成练习',
            estimatedHours: 0.8,
            completed: true,
            practiceSuggestion: '完成一个练习',
          },
        ],
      },
      {
        date: '2026-06-02',
        goal: '第 2 天：React 基础 — 入门阶段学习',
        tasks: [
          {
            id: 't3',
            title: 'React 语法',
            description: '学习语法',
            estimatedHours: 1.2,
            completed: false,
          },
          {
            id: 't4',
            title: '项目实践',
            description: '小项目',
            estimatedHours: 0.8,
            completed: false,
          },
        ],
      },
    ],
  }
}

export function createSecondPlan(): LearningPlan {
  return {
    id: 'plan-2',
    title: '线性代数复习',
    startDate: '2026-06-02',
    days: 1,
    dailyHours: 1.5,
    createdAt: '2026-06-01T09:00:00.000Z',
    dailyPlans: [
      {
        date: '2026-06-02',
        goal: '第 1 天：线性代数复习',
        tasks: [
          {
            id: 't5',
            title: '矩阵运算',
            description: '复习矩阵',
            estimatedHours: 1.5,
            completed: false,
          },
        ],
      },
    ],
  }
}

import { describe, expect, it } from 'vitest'
import { generatePlan, validatePlanForm } from './planGenerator'
import type { PlanFormData } from '../types'

const validForm: PlanFormData = {
  title: 'React 基础',
  notes: '有 JS 基础',
  startDate: '2026-06-01',
  days: 7,
  dailyHours: 2,
  customDailyContent: '',
}

describe('validatePlanForm', () => {
  it('returns no errors for valid form', () => {
    expect(validatePlanForm(validForm)).toEqual({})
  })

  it('rejects empty title', () => {
    const errors = validatePlanForm({ ...validForm, title: '  ' })
    expect(errors.title).toBe('学习主题不能为空')
  })

  it('rejects days less than 1', () => {
    const errors = validatePlanForm({ ...validForm, days: 0 })
    expect(errors.days).toBe('计划天数不能小于 1')
  })

  it('rejects days greater than 90', () => {
    const errors = validatePlanForm({ ...validForm, days: 91 })
    expect(errors.days).toBe('计划天数不能超过 90 天')
  })

  it('rejects daily hours below 0.5', () => {
    const errors = validatePlanForm({ ...validForm, dailyHours: 0.3 })
    expect(errors.dailyHours).toBe('每日可用时长不能小于 0.5 小时')
  })

  it('rejects daily hours above 6', () => {
    const errors = validatePlanForm({ ...validForm, dailyHours: 7 })
    expect(errors.dailyHours).toBe('每日可用时长不能超过 6 小时')
  })
})

describe('generatePlan', () => {
  it('generates structured daily plans with correct dates', () => {
    const plan = generatePlan(validForm)
    expect(plan.title).toBe('React 基础')
    expect(plan.dailyPlans).toHaveLength(7)
    expect(plan.dailyPlans[0].date).toBe('2026-06-01')
    expect(plan.dailyPlans[6].date).toBe('2026-06-07')
  })

  it('each day has goal and tasks with required fields', () => {
    const plan = generatePlan(validForm)
    for (const daily of plan.dailyPlans) {
      expect(daily.goal).toBeTruthy()
      expect(daily.tasks.length).toBeGreaterThan(0)
      for (const task of daily.tasks) {
        expect(task.id).toBeTruthy()
        expect(task.title).toBeTruthy()
        expect(task.description).toBeTruthy()
        expect(task.estimatedHours).toBeGreaterThan(0)
        expect(task.completed).toBe(false)
      }
    }
  })

  it('uses custom daily content when provided', () => {
    const plan = generatePlan({ ...validForm, customDailyContent: '阅读官方文档' })
    expect(plan.dailyPlans[0].tasks[0].title).toBe('阅读官方文档')
  })
})

import { describe, expect, it } from 'vitest'
import {
  addPlan,
  deletePlan,
  loadPlans,
  savePlans,
  updateTaskCompletion,
} from './plans'
import { createMockPlan, createSecondPlan } from '../test/fixtures'

describe('plans storage', () => {
  it('returns empty array when no data saved', () => {
    expect(loadPlans()).toEqual([])
  })

  it('persists multiple plans without overwriting', () => {
    const plan1 = createMockPlan()
    const plan2 = createSecondPlan()
    addPlan(plan1)
    addPlan(plan2)
    const loaded = loadPlans()
    expect(loaded).toHaveLength(2)
    expect(loaded.map((p) => p.id)).toEqual(['plan-1', 'plan-2'])
  })

  it('persists completion state after update', () => {
    const plan = createMockPlan()
    savePlans([plan])
    updateTaskCompletion('plan-1', '2026-06-01', 't1', true)
    const reloaded = loadPlans()
    const task = reloaded[0].dailyPlans[0].tasks.find((t) => t.id === 't1')
    expect(task?.completed).toBe(true)
  })

  it('removes plan on delete and updates storage', () => {
    savePlans([createMockPlan(), createSecondPlan()])
    deletePlan('plan-1')
    expect(loadPlans()).toHaveLength(1)
    expect(loadPlans()[0].id).toBe('plan-2')
  })
})

import { describe, expect, it } from 'vitest'
import {
  aggregateCalendarDays,
  getAdjacentTaskDate,
  getDayPlanEntries,
  getDayTotalHours,
} from './calendarAggregate'
import { createMockPlan, createSecondPlan } from '../test/fixtures'

describe('calendarAggregate', () => {
  const plan1 = createMockPlan()
  const plan2 = createSecondPlan()
  const plans = [plan1, plan2]

  it('merges multiple plans on the same date', () => {
    const map = aggregateCalendarDays(plans)
    const june2 = map.get('2026-06-02')
    expect(june2).toBeDefined()
    expect(june2!.planIds).toHaveLength(2)
    expect(june2!.taskCount).toBe(3)
    expect(june2!.totalHours).toBe(3.5)
  })

  it('returns all plan entries for a date', () => {
    const entries = getDayPlanEntries(plans, '2026-06-02')
    expect(entries).toHaveLength(2)
    expect(entries.map((e) => e.planTitle)).toEqual(['React 基础', '线性代数复习'])
  })

  it('calculates total hours for a day', () => {
    const entries = getDayPlanEntries(plans, '2026-06-02')
    expect(getDayTotalHours(entries)).toBe(3.5)
  })

  it('navigates to adjacent dates with tasks', () => {
    expect(getAdjacentTaskDate(plans, '2026-06-02', 'prev')).toBe('2026-06-01')
    expect(getAdjacentTaskDate(plans, '2026-06-01', 'next')).toBe('2026-06-02')
    expect(getAdjacentTaskDate(plans, '2026-06-02', 'next')).toBeNull()
  })
})

import { describe, expect, it } from 'vitest'
import { calculateProgress, getPlanProgress } from './progress'
import { createMockPlan, createSecondPlan } from '../test/fixtures'

describe('progress', () => {
  it('calculates global completion rate', () => {
    const stats = calculateProgress([createMockPlan(), createSecondPlan()])
    expect(stats.planCount).toBe(2)
    expect(stats.totalTasks).toBe(5)
    expect(stats.completedTasks).toBe(1)
    expect(stats.completionRate).toBe(20)
  })

  it('uses unique dates for totalDays', () => {
    const stats = calculateProgress([createMockPlan(), createSecondPlan()])
    expect(stats.totalDays).toBe(2)
  })

  it('calculates per-plan progress', () => {
    const progress = getPlanProgress(createMockPlan())
    expect(progress.completed).toBe(1)
    expect(progress.total).toBe(4)
    expect(progress.rate).toBe(25)
  })
})

