import type { LearningPlan, LearningSuggestion } from '../types'
import { aggregateCalendarDays } from './calendarAggregate'
import { calculateProgress } from './progress'
import { formatDisplayDate } from './dates'

const OVERLOAD_HOURS = 5
const WEEKLY_HOURS_WARNING = 16

function getWeekDates(from: string): string[] {
  const dates: string[] = []
  const start = new Date(from)
  for (let i = 0; i < 7; i++) {
    const d = new Date(start)
    d.setDate(start.getDate() + i)
    const y = d.getFullYear()
    const m = String(d.getMonth() + 1).padStart(2, '0')
    const day = String(d.getDate()).padStart(2, '0')
    dates.push(`${y}-${m}-${day}`)
  }
  return dates
}

function getUpcomingWeekStart(): string {
  const today = new Date()
  const y = today.getFullYear()
  const m = String(today.getMonth() + 1).padStart(2, '0')
  const d = String(today.getDate()).padStart(2, '0')
  return `${y}-${m}-${d}`
}

export function generateLearningSuggestions(plans: LearningPlan[]): LearningSuggestion[] {
  if (plans.length === 0) return []

  const suggestions: LearningSuggestion[] = []
  const stats = calculateProgress(plans)
  const aggregated = aggregateCalendarDays(plans)
  const weekStart = getUpcomingWeekStart()
  const weekDates = getWeekDates(weekStart)

  let weeklyHours = 0
  const overloadedDays: { date: string; hours: number }[] = []

  for (const date of weekDates) {
    const day = aggregated.get(date)
    if (day) {
      weeklyHours += day.totalHours
      if (day.totalHours > OVERLOAD_HOURS) {
        overloadedDays.push({ date, hours: day.totalHours })
      }
    }
  }

  suggestions.push({
    id: 'weekly-summary',
    type: 'info',
    title: '本周学习概览',
    content: `你当前有 ${stats.planCount} 个学习计划，本周（从 ${weekStart} 起）预计学习 ${Math.round(weeklyHours * 10) / 10} 小时，共 ${stats.totalTasks} 项任务，已完成 ${stats.completedTasks} 项（${stats.completionRate}%）。`,
  })

  for (const { date, hours } of overloadedDays) {
    suggestions.push({
      id: `overload-${date}`,
      type: 'warning',
      title: '学习负载偏高',
      content: `${formatDisplayDate(date)} 安排了 ${hours} 小时任务，超过建议的 ${OVERLOAD_HOURS} 小时。建议将部分练习移动到相邻日期，或降低单日任务密度。`,
    })
  }

  if (weeklyHours > WEEKLY_HOURS_WARNING) {
    suggestions.push({
      id: 'weekly-overload',
      type: 'warning',
      title: '本周总时长较高',
      content: `本周预计学习 ${Math.round(weeklyHours * 10) / 10} 小时，超过 ${WEEKLY_HOURS_WARNING} 小时。建议适当调整计划节奏，留出复习与休息时间。`,
    })
  }

  for (const plan of plans) {
    const total = plan.dailyPlans.reduce((s, d) => s + d.tasks.length, 0)
    const done = plan.dailyPlans.reduce(
      (s, d) => s + d.tasks.filter((t) => t.completed).length,
      0,
    )
    const pending = total - done
    if (pending > 0 && done > 0 && done / total < 0.5) {
      suggestions.push({
        id: `lag-${plan.id}`,
        type: 'info',
        title: `「${plan.title}」进度提醒`,
        content: `该计划完成 ${done}/${total} 项任务。建议优先完成近期日期的任务，避免学习进度滞后。`,
      })
    }
  }

  if (stats.completionRate >= 80 && stats.totalTasks > 0) {
    suggestions.push({
      id: 'good-progress',
      type: 'success',
      title: '学习进展良好',
      content: `整体完成率已达 ${stats.completionRate}%，继续保持！可适当增加练习深度或开始下一个学习主题。`,
    })
  }

  if (stats.completionRate === 0 && stats.totalTasks > 0) {
    suggestions.push({
      id: 'get-started',
      type: 'info',
      title: '开始你的学习',
      content: '尚未完成任何任务。建议从最近一天的任务开始，勾选完成项以跟踪进度。',
    })
  }

  return suggestions
}

import type { DayPlanEntry, DailyRefinement, RefinementChecklistItem } from '../types'
import { formatDisplayDate } from './dates'
import { getDayTotalHours } from './calendarAggregate'

function generateId(): string {
  return crypto.randomUUID()
}

const MATERIAL_HINTS: Record<string, string> = {
  React: 'React 官方文档（react.dev）与对应章节教程',
  线性代数: '线性代数教材对应章节与 Khan Academy 视频',
  英语: '精选英文文章或原版书籍章节',
  机器学习: '吴恩达课程笔记与 scikit-learn 文档',
}

function guessMaterial(planTitle: string, taskTitle: string): string {
  for (const [key, hint] of Object.entries(MATERIAL_HINTS)) {
    if (planTitle.includes(key) || taskTitle.includes(key)) {
      return hint
    }
  }
  return `与「${planTitle}」相关的官方文档、教程或教材章节`
}

export function refineDailyPlan(date: string, entries: DayPlanEntry[]): DailyRefinement {
  const totalHours = getDayTotalHours(entries)
  const lines: string[] = [
    `## ${formatDisplayDate(date)} 详细计划`,
    '',
    `> 当天共 ${entries.length} 个计划，预计 ${totalHours} 小时`,
    '',
  ]

  const checklist: RefinementChecklistItem[] = []

  for (const entry of entries) {
    lines.push(`### ${entry.planTitle}`)
    lines.push('')
    lines.push(`**学习目标：** ${entry.dailyPlan.goal}`)
    lines.push('')

    lines.push('#### 学习材料')
    entry.dailyPlan.tasks.forEach((task, i) => {
      lines.push(`${i + 1}. ${guessMaterial(entry.planTitle, task.title)} — 用于「${task.title}」`)
    })
    lines.push('')

    lines.push('#### 具体练习')
    entry.dailyPlan.tasks.forEach((task, i) => {
      const practice = task.practiceSuggestion ?? `完成与「${task.title}」相关的动手练习`
      lines.push(`${i + 1}. ${practice}（预计 ${task.estimatedHours}h）`)
    })
    lines.push('')

    lines.push('#### 完成标准')
    for (const task of entry.dailyPlan.tasks) {
      const criterion = `能独立说明并完成「${task.title}」相关练习`
      lines.push(`- ${criterion}`)
      checklist.push({
        id: generateId(),
        text: `[${entry.planTitle}] ${criterion}`,
        completed: false,
      })
    }
    lines.push('')
  }

  lines.push('---')
  lines.push('*由 AI 学习助手根据当天任务自动生成，可按实际情况调整。*')

  return {
    date,
    markdown: lines.join('\n'),
    checklist,
    generatedAt: new Date().toISOString(),
  }
}

import type { DailyRefinement } from '../types'

const STORAGE_KEY = 'daily-refinements'

export function loadRefinements(): Record<string, DailyRefinement> {
  try {
    const raw = localStorage.getItem(STORAGE_KEY)
    if (!raw) return {}
    return JSON.parse(raw) as Record<string, DailyRefinement>
  } catch {
    return {}
  }
}

export function saveRefinement(refinement: DailyRefinement): void {
  const all = loadRefinements()
  all[refinement.date] = refinement
  localStorage.setItem(STORAGE_KEY, JSON.stringify(all))
}

export function getRefinement(date: string): DailyRefinement | undefined {
  return loadRefinements()[date]
}

export function updateRefinementChecklist(
  date: string,
  itemId: string,
  completed: boolean,
): DailyRefinement | undefined {
  const all = loadRefinements()
  const refinement = all[date]
  if (!refinement) return undefined

  const item = refinement.checklist.find((c) => c.id === itemId)
  if (!item) return refinement

  item.completed = completed
  all[date] = refinement
  localStorage.setItem(STORAGE_KEY, JSON.stringify(all))
  return refinement
}

export function deleteRefinement(date: string): void {
  const all = loadRefinements()
  delete all[date]
  localStorage.setItem(STORAGE_KEY, JSON.stringify(all))
}

import { useMemo } from 'react'
import type { LearningPlan } from '../types'
import { generateLearningSuggestions } from '../utils/aiSuggestions'

interface AiSuggestionsPanelProps {
  plans: LearningPlan[]
}

const typeStyles = {
  warning: 'border-amber-200 bg-amber-50 text-amber-900',
  info: 'border-blue-200 bg-blue-50 text-blue-900',
  success: 'border-green-200 bg-green-50 text-green-900',
}

const typeIcons = {
  warning: '⚠️',
  info: '💡',
  success: '✅',
}

export function AiSuggestionsPanel({ plans }: AiSuggestionsPanelProps) {
  const suggestions = useMemo(() => generateLearningSuggestions(plans), [plans])

  if (plans.length === 0) return null

  return (
    <section className="rounded-xl border border-slate-200 bg-white p-4 shadow-sm">
      <div className="mb-3 flex items-center gap-2">
        <span className="text-lg">🤖</span>
        <h2 className="text-lg font-semibold text-slate-800">AI 学习建议</h2>
      </div>
      <div className="space-y-3">
        {suggestions.map((s) => (
          <article
            key={s.id}
            className={`rounded-lg border p-3 ${typeStyles[s.type]}`}
          >
            <h3 className="text-sm font-semibold">
              {typeIcons[s.type]} {s.title}
            </h3>
            <p className="mt-1 text-sm leading-relaxed opacity-90">{s.content}</p>
          </article>
        ))}
      </div>
    </section>
  )
}

import { useState } from 'react'
import type { DailyRefinement } from '../types'
import {
  deleteRefinement,
  saveRefinement,
  updateRefinementChecklist,
} from '../storage/refinements'
import { refineDailyPlan } from '../utils/aiDailyRefinement'
import type { DayPlanEntry } from '../types'

interface DailyRefinementPanelProps {
  date: string
  entries: DayPlanEntry[]
  initialRefinement?: DailyRefinement
  onRefinementChange: (refinement: DailyRefinement | undefined) => void
}

export function DailyRefinementPanel({
  date,
  entries,
  initialRefinement,
  onRefinementChange,
}: DailyRefinementPanelProps) {
  const [refinement, setRefinement] = useState<DailyRefinement | undefined>(
    initialRefinement,
  )
  const [loading, setLoading] = useState(false)

  const handleGenerate = async () => {
    setLoading(true)
    await new Promise((r) => setTimeout(r, 400))
    const result = refineDailyPlan(date, entries)
    saveRefinement(result)
    setRefinement(result)
    onRefinementChange(result)
    setLoading(false)
  }

  const handleToggleChecklist = (itemId: string, completed: boolean) => {
    const updated = updateRefinementChecklist(date, itemId, completed)
    if (updated) {
      setRefinement(updated)
      onRefinementChange(updated)
    }
  }

  const handleClear = () => {
    deleteRefinement(date)
    setRefinement(undefined)
    onRefinementChange(undefined)
  }

  return (
    <section className="rounded-xl border border-indigo-200 bg-white p-5 shadow-sm">
      <div className="mb-4 flex flex-wrap items-center justify-between gap-2">
        <h2 className="text-lg font-semibold text-slate-800">AI 每日计划细化</h2>
        <div className="flex gap-2">
          <button
            type="button"
            onClick={handleGenerate}
            disabled={loading}
            className="rounded-lg bg-indigo-600 px-4 py-2 text-sm font-medium text-white hover:bg-indigo-700 disabled:opacity-60"
          >
            {loading ? '生成中…' : refinement ? '重新生成' : '细化当天计划'}
          </button>
          {refinement && (
            <button
              type="button"
              onClick={handleClear}
              className="rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-600 hover:bg-slate-50"
            >
              清除
            </button>
          )}
        </div>
      </div>

      {!refinement && !loading && (
        <p className="text-sm text-slate-500">
          点击「细化当天计划」，AI 将根据当天所有任务生成学习材料、具体练习和完成标准。
        </p>
      )}

      {loading && (
        <p className="animate-pulse text-sm text-indigo-600">正在分析当天任务并生成详细计划…</p>
      )}

      {refinement && !loading && (
        <div className="space-y-4">
          <pre className="max-h-80 overflow-auto whitespace-pre-wrap rounded-lg bg-slate-50 p-4 font-sans text-sm leading-relaxed text-slate-700">
            {refinement.markdown}
          </pre>

          {refinement.checklist.length > 0 && (
            <div>
              <h3 className="mb-2 text-sm font-semibold text-slate-700">完成标准清单</h3>
              <ul className="space-y-2">
                {refinement.checklist.map((item) => (
                  <li key={item.id} className="flex items-start gap-2">
                    <input
                      type="checkbox"
                      checked={item.completed}
                      onChange={(e) => handleToggleChecklist(item.id, e.target.checked)}
                      className="mt-0.5 h-4 w-4 rounded border-slate-300 text-indigo-600"
                    />
                    <span
                      className={`text-sm ${
                        item.completed ? 'text-slate-400 line-through' : 'text-slate-700'
                      }`}
                    >
                      {item.text}
                    </span>
                  </li>
                ))}
              </ul>
            </div>
          )}

          <p className="text-xs text-slate-400">
            生成于 {new Date(refinement.generatedAt).toLocaleString('zh-CN')}
          </p>
        </div>
      )}
    </section>
  )
}

