const DEFAULT_BASE = 'https://api.openai.com/v1'
const DEFAULT_MODEL = 'gpt-4o-mini'

export function isAiConfigured() {
  return Boolean(process.env.AI_API_KEY?.trim())
}

function getConfig() {
  return {
    apiKey: process.env.AI_API_KEY?.trim(),
    baseUrl: (process.env.AI_API_BASE?.trim() || DEFAULT_BASE).replace(/\/$/, ''),
    model: process.env.AI_MODEL?.trim() || DEFAULT_MODEL,
  }
}

async function chatCompletion(messages, { temperature = 0.7 } = {}) {
  const { apiKey, baseUrl, model } = getConfig()
  if (!apiKey) {
    throw new Error('AI_API_KEY 未配置')
  }

  const response = await fetch(`${baseUrl}/chat/completions`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${apiKey}`,
    },
    body: JSON.stringify({
      model,
      temperature,
      messages,
      response_format: { type: 'json_object' },
    }),
  })

  if (!response.ok) {
    const text = await response.text()
    throw new Error(`AI API 错误 (${response.status}): ${text.slice(0, 300)}`)
  }

  const data = await response.json()
  const content = data.choices?.[0]?.message?.content
  if (!content) {
    throw new Error('AI API 返回内容为空')
  }

  return JSON.parse(content)
}

export async function generateSuggestionsFromAi(planSummary) {
  const system = `你是学习计划助手。根据用户的学习计划摘要，生成 2-5 条实用建议。
必须返回 JSON：
{
  "suggestions": [
    { "id": "唯一字符串", "type": "warning"|"info"|"success", "title": "标题", "content": "具体建议内容" }
  ]
}
要求：
- 分析计划数量、本周时长、完成率、单日负载
- 单日超过 5 小时要 warning
- 完成率低或进度滞后要 info
- 完成率高可 success
- 内容用中文，具体可执行`

  const user = `学习计划摘要（JSON）：\n${JSON.stringify(planSummary, null, 2)}`

  const result = await chatCompletion([
    { role: 'system', content: system },
    { role: 'user', content: user },
  ])

  if (!Array.isArray(result.suggestions)) {
    throw new Error('AI 返回格式无效：缺少 suggestions 数组')
  }

  return result.suggestions.map((s, i) => ({
    id: String(s.id || `ai-${i}`),
    type: ['warning', 'info', 'success'].includes(s.type) ? s.type : 'info',
    title: String(s.title || '学习建议'),
    content: String(s.content || ''),
  }))
}

export async function refineDailyPlanFromAi(date, dayContext) {
  const system = `你是学习计划细化助手。根据某天的学习任务，生成详细 Markdown 学习计划。
必须返回 JSON：
{
  "markdown": "完整 Markdown 字符串，含 ## 标题、### 学习材料、### 具体练习、### 完成标准",
  "checklist": ["可勾选的完成标准1", "完成标准2"]
}
要求：
- markdown 用中文
- 学习材料要具体（文档/教程名称）
- 练习要可执行
- checklist 从完成标准提炼，3-8 条`

  const user = `日期：${date}\n当天任务（JSON）：\n${JSON.stringify(dayContext, null, 2)}`

  const result = await chatCompletion(
    [
      { role: 'system', content: system },
      { role: 'user', content: user },
    ],
    { temperature: 0.8 },
  )

  if (!result.markdown || !Array.isArray(result.checklist)) {
    throw new Error('AI 返回格式无效：需要 markdown 和 checklist')
  }

  return {
    markdown: String(result.markdown),
    checklist: result.checklist.map((text, i) => ({
      id: `ai-check-${i}-${Date.now()}`,
      text: String(text),
      completed: false,
    })),
  }
}

import 'dotenv/config'
import express from 'express'
import cors from 'cors'
import {
  generateSuggestionsFromAi,
  isAiConfigured,
  refineDailyPlanFromAi,
} from './ai.mjs'

const app = express()
const PORT = Number(process.env.PORT) || 3001

app.use(cors())
app.use(express.json({ limit: '1mb' }))

app.get('/api/health', (_req, res) => {
  res.json({ ok: true, aiConfigured: isAiConfigured() })
})

app.get('/api/ai/status', (_req, res) => {
  res.json({
    configured: isAiConfigured(),
    model: process.env.AI_MODEL || 'gpt-4o-mini',
    baseUrl: process.env.AI_API_BASE || 'https://api.openai.com/v1',
  })
})

app.post('/api/ai/suggestions', async (req, res) => {
  try {
    if (!isAiConfigured()) {
      return res.status(503).json({ error: 'AI_API_KEY 未配置，请在 .env 中设置' })
    }
    const { planSummary } = req.body
    if (!planSummary) {
      return res.status(400).json({ error: '缺少 planSummary' })
    }
    const suggestions = await generateSuggestionsFromAi(planSummary)
    res.json({ suggestions, source: 'ai' })
  } catch (err) {
    console.error('[AI suggestions]', err)
    res.status(500).json({ error: err instanceof Error ? err.message : '生成失败' })
  }
})

app.post('/api/ai/refine-daily', async (req, res) => {
  try {
    if (!isAiConfigured()) {
      return res.status(503).json({ error: 'AI_API_KEY 未配置，请在 .env 中设置' })
    }
    const { date, dayContext } = req.body
    if (!date || !dayContext) {
      return res.status(400).json({ error: '缺少 date 或 dayContext' })
    }
    const result = await refineDailyPlanFromAi(date, dayContext)
    res.json({
      refinement: {
        date,
        markdown: result.markdown,
        checklist: result.checklist,
        generatedAt: new Date().toISOString(),
        source: 'ai',
      },
    })
  } catch (err) {
    console.error('[AI refine-daily]', err)
    res.status(500).json({ error: err instanceof Error ? err.message : '生成失败' })
  }
})

app.listen(PORT, () => {
  console.log(`API server http://localhost:${PORT}`)
  console.log(`AI configured: ${isAiConfigured()}`)
})

import type { LearningPlan, LearningSuggestion, DayPlanEntry, DailyRefinement } from '../types'
import { aggregateCalendarDays } from './calendarAggregate'
import { calculateProgress } from './progress'
import { formatDisplayDate } from './dates'
import { getDayTotalHours } from './calendarAggregate'

const OVERLOAD_HOURS = 5
const WEEKLY_HOURS_WARNING = 16

function getWeekDates(from: string): string[] {
  const dates: string[] = []
  const start = new Date(from)
  for (let i = 0; i < 7; i++) {
    const d = new Date(start)
    d.setDate(start.getDate() + i)
    const y = d.getFullYear()
    const m = String(d.getMonth() + 1).padStart(2, '0')
    const day = String(d.getDate()).padStart(2, '0')
    dates.push(`${y}-${m}-${day}`)
  }
  return dates
}

function getUpcomingWeekStart(): string {
  const today = new Date()
  const y = today.getFullYear()
  const m = String(today.getMonth() + 1).padStart(2, '0')
  const d = String(today.getDate()).padStart(2, '0')
  return `${y}-${m}-${d}`
}

/** 构建发给 AI 的精简摘要 */
export function buildPlanSummaryForAi(plans: LearningPlan[]) {
  const stats = calculateProgress(plans)
  const aggregated = aggregateCalendarDays(plans)
  const weekStart = getUpcomingWeekStart()
  const weekDates = getWeekDates(weekStart)

  let weeklyHours = 0
  const dailyLoads: { date: string; hours: number; plans: string[] }[] = []

  for (const date of weekDates) {
    const day = aggregated.get(date)
    if (day) {
      weeklyHours += day.totalHours
      dailyLoads.push({
        date,
        hours: day.totalHours,
        plans: day.planTitles,
      })
    }
  }

  return {
    planCount: stats.planCount,
    totalTasks: stats.totalTasks,
    completedTasks: stats.completedTasks,
    completionRate: stats.completionRate,
    weeklyHours: Math.round(weeklyHours * 10) / 10,
    weekStart,
    overloadThreshold: OVERLOAD_HOURS,
    weeklyWarningThreshold: WEEKLY_HOURS_WARNING,
    dailyLoads,
    plans: plans.map((p) => {
      const total = p.dailyPlans.reduce((s, d) => s + d.tasks.length, 0)
      const done = p.dailyPlans.reduce(
        (s, d) => s + d.tasks.filter((t) => t.completed).length,
        0,
      )
      return {
        title: p.title,
        startDate: p.startDate,
        days: p.days,
        dailyHours: p.dailyHours,
        notes: p.notes,
        completedTasks: done,
        totalTasks: total,
        completionRate: total > 0 ? Math.round((done / total) * 100) : 0,
      }
    }),
  }
}

/** 本地规则引擎（AI 不可用时的降级方案） */
export function generateLearningSuggestionsLocal(plans: LearningPlan[]): LearningSuggestion[] {
  if (plans.length === 0) return []

  const suggestions: LearningSuggestion[] = []
  const stats = calculateProgress(plans)
  const aggregated = aggregateCalendarDays(plans)
  const weekStart = getUpcomingWeekStart()
  const weekDates = getWeekDates(weekStart)

  let weeklyHours = 0
  const overloadedDays: { date: string; hours: number }[] = []

  for (const date of weekDates) {
    const day = aggregated.get(date)
    if (day) {
      weeklyHours += day.totalHours
      if (day.totalHours > OVERLOAD_HOURS) {
        overloadedDays.push({ date, hours: day.totalHours })
      }
    }
  }

  suggestions.push({
    id: 'weekly-summary',
    type: 'info',
    title: '本周学习概览',
    content: `你当前有 ${stats.planCount} 个学习计划，本周（从 ${weekStart} 起）预计学习 ${Math.round(weeklyHours * 10) / 10} 小时，共 ${stats.totalTasks} 项任务，已完成 ${stats.completedTasks} 项（${stats.completionRate}%）。`,
  })

  for (const { date, hours } of overloadedDays) {
    suggestions.push({
      id: `overload-${date}`,
      type: 'warning',
      title: '学习负载偏高',
      content: `${formatDisplayDate(date)} 安排了 ${hours} 小时任务，超过建议的 ${OVERLOAD_HOURS} 小时。建议将部分练习移动到相邻日期，或降低单日任务密度。`,
    })
  }

  if (weeklyHours > WEEKLY_HOURS_WARNING) {
    suggestions.push({
      id: 'weekly-overload',
      type: 'warning',
      title: '本周总时长较高',
      content: `本周预计学习 ${Math.round(weeklyHours * 10) / 10} 小时，超过 ${WEEKLY_HOURS_WARNING} 小时。建议适当调整计划节奏，留出复习与休息时间。`,
    })
  }

  for (const plan of plans) {
    const total = plan.dailyPlans.reduce((s, d) => s + d.tasks.length, 0)
    const done = plan.dailyPlans.reduce(
      (s, d) => s + d.tasks.filter((t) => t.completed).length,
      0,
    )
    if (total - done > 0 && done > 0 && done / total < 0.5) {
      suggestions.push({
        id: `lag-${plan.id}`,
        type: 'info',
        title: `「${plan.title}」进度提醒`,
        content: `该计划完成 ${done}/${total} 项任务。建议优先完成近期日期的任务，避免学习进度滞后。`,
      })
    }
  }

  if (stats.completionRate >= 80 && stats.totalTasks > 0) {
    suggestions.push({
      id: 'good-progress',
      type: 'success',
      title: '学习进展良好',
      content: `整体完成率已达 ${stats.completionRate}%，继续保持！`,
    })
  }

  if (stats.completionRate === 0 && stats.totalTasks > 0) {
    suggestions.push({
      id: 'get-started',
      type: 'info',
      title: '开始你的学习',
      content: '尚未完成任何任务。建议从最近一天的任务开始，勾选完成项以跟踪进度。',
    })
  }

  return suggestions
}

/** @deprecated 使用 fetchLearningSuggestions */
export const generateLearningSuggestions = generateLearningSuggestionsLocal

export function buildDayContextForAi(date: string, entries: DayPlanEntry[]) {
  return {
    date,
    displayDate: formatDisplayDate(date),
    totalHours: getDayTotalHours(entries),
    planCount: entries.length,
    plans: entries.map((e) => ({
      planTitle: e.planTitle,
      goal: e.dailyPlan.goal,
      tasks: e.dailyPlan.tasks.map((t) => ({
        title: t.title,
        description: t.description,
        estimatedHours: t.estimatedHours,
        completed: t.completed,
        practiceSuggestion: t.practiceSuggestion,
      })),
    })),
  }
}

