import type { DayPlanEntry, DailyRefinement, LearningPlan, LearningSuggestion } from '../types'
import {
  buildDayContextForAi,
  buildPlanSummaryForAi,
  generateLearningSuggestionsLocal,
} from '../utils/aiSuggestions'
import { refineDailyPlanLocal } from '../utils/aiDailyRefinement'

export type AiSource = 'ai' | 'local'

export interface AiResult<T> {
  data: T
  source: AiSource
  error?: string
}

async function postJson<T>(url: string, body: unknown): Promise<T> {
  const res = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  })
  const payload = await res.json().catch(() => ({}))
  if (!res.ok) {
    throw new Error(payload.error || `请求失败 (${res.status})`)
  }
  return payload as T
}

export async function checkAiStatus(): Promise<{ configured: boolean }> {
  try {
    const res = await fetch('/api/ai/status')
    if (!res.ok) return { configured: false }
    return res.json()
  } catch {
    return { configured: false }
  }
}

export async function fetchLearningSuggestions(
  plans: LearningPlan[],
): Promise<AiResult<LearningSuggestion[]>> {
  const planSummary = buildPlanSummaryForAi(plans)
  try {
    const result = await postJson<{ suggestions: LearningSuggestion[]; source: AiSource }>(
      '/api/ai/suggestions',
      { planSummary },
    )
    return { data: result.suggestions, source: result.source || 'ai' }
  } catch (err) {
    const message = err instanceof Error ? err.message : 'AI 服务不可用'
    return {
      data: generateLearningSuggestionsLocal(plans),
      source: 'local',
      error: message,
    }
  }
}

export async function fetchDailyRefinement(
  date: string,
  entries: DayPlanEntry[],
): Promise<AiResult<DailyRefinement>> {
  const dayContext = buildDayContextForAi(date, entries)
  try {
    const result = await postJson<{ refinement: DailyRefinement }>('/api/ai/refine-daily', {
      date,
      dayContext,
    })
    return { data: result.refinement, source: result.refinement.source || 'ai' }
  } catch (err) {
    const message = err instanceof Error ? err.message : 'AI 服务不可用'
    return {
      data: refineDailyPlanLocal(date, entries),
      source: 'local',
      error: message,
    }
  }
}

import { useCallback, useEffect, useState } from 'react'
import type { LearningPlan, LearningSuggestion } from '../types'
import { fetchLearningSuggestions, checkAiStatus, type AiSource } from '../services/aiApi'

interface AiSuggestionsPanelProps {
  plans: LearningPlan[]
}

const typeStyles = {
  warning: 'border-amber-200 bg-amber-50 text-amber-900',
  info: 'border-blue-200 bg-blue-50 text-blue-900',
  success: 'border-green-200 bg-green-50 text-green-900',
}

const typeIcons = {
  warning: '⚠️',
  info: '💡',
  success: '✅',
}

export function AiSuggestionsPanel({ plans }: AiSuggestionsPanelProps) {
  const [suggestions, setSuggestions] = useState<LearningSuggestion[]>([])
  const [loading, setLoading] = useState(false)
  const [source, setSource] = useState<AiSource>('local')
  const [error, setError] = useState<string | null>(null)
  const [aiConfigured, setAiConfigured] = useState(false)

  const loadSuggestions = useCallback(async () => {
    if (plans.length === 0) return
    setLoading(true)
    setError(null)
    const result = await fetchLearningSuggestions(plans)
    setSuggestions(result.data)
    setSource(result.source)
    if (result.error) setError(result.error)
    setLoading(false)
  }, [plans])

  useEffect(() => {
    checkAiStatus().then((s) => setAiConfigured(s.configured))
  }, [])

  useEffect(() => {
    loadSuggestions()
  }, [loadSuggestions])

  if (plans.length === 0) return null

  return (
    <section className="rounded-xl border border-slate-200 bg-white p-4 shadow-sm">
      <div className="mb-3 flex flex-wrap items-center justify-between gap-2">
        <div className="flex items-center gap-2">
          <span className="text-lg">🤖</span>
          <h2 className="text-lg font-semibold text-slate-800">AI 学习建议</h2>
          <span
            className={`rounded-full px-2 py-0.5 text-xs ${
              source === 'ai'
                ? 'bg-indigo-100 text-indigo-700'
                : 'bg-slate-100 text-slate-600'
            }`}
          >
            {source === 'ai' ? '大模型' : '本地规则'}
          </span>
        </div>
        <button
          type="button"
          onClick={loadSuggestions}
          disabled={loading}
          className="rounded-lg border border-slate-200 px-3 py-1 text-xs text-slate-600 hover:bg-slate-50 disabled:opacity-50"
        >
          {loading ? '生成中…' : '刷新建议'}
        </button>
      </div>

      {!aiConfigured && (
        <p className="mb-3 rounded-lg bg-amber-50 px-3 py-2 text-xs text-amber-800">
          未检测到 AI API 配置。请在项目根目录创建 <code className="font-mono">.env</code> 并设置{' '}
          <code className="font-mono">AI_API_KEY</code>，然后运行 <code className="font-mono">npm run dev:all</code>
          。当前使用本地规则降级。
        </p>
      )}

      {error && source === 'local' && aiConfigured && (
        <p className="mb-3 rounded-lg bg-red-50 px-3 py-2 text-xs text-red-700">
          AI 调用失败，已降级为本地规则：{error}
        </p>
      )}

      {loading && suggestions.length === 0 ? (
        <p className="animate-pulse text-sm text-indigo-600">正在调用 AI 分析学习计划…</p>
      ) : (
        <div className="space-y-3">
          {suggestions.map((s) => (
            <article
              key={s.id}
              className={`rounded-lg border p-3 ${typeStyles[s.type]}`}
            >
              <h3 className="text-sm font-semibold">
                {typeIcons[s.type]} {s.title}
              </h3>
              <p className="mt-1 text-sm leading-relaxed opacity-90">{s.content}</p>
            </article>
          ))}
        </div>
      )}
    </section>
  )
}

import { useState } from 'react'
import type { DailyRefinement } from '../types'
import {
  deleteRefinement,
  saveRefinement,
  updateRefinementChecklist,
} from '../storage/refinements'
import { fetchDailyRefinement, type AiSource } from '../services/aiApi'
import type { DayPlanEntry } from '../types'

interface DailyRefinementPanelProps {
  date: string
  entries: DayPlanEntry[]
  initialRefinement?: DailyRefinement
  onRefinementChange: (refinement: DailyRefinement | undefined) => void
}

export function DailyRefinementPanel({
  date,
  entries,
  initialRefinement,
  onRefinementChange,
}: DailyRefinementPanelProps) {
  const [refinement, setRefinement] = useState<DailyRefinement | undefined>(
    initialRefinement,
  )
  const [loading, setLoading] = useState(false)
  const [source, setSource] = useState<AiSource>(initialRefinement?.source ?? 'local')
  const [error, setError] = useState<string | null>(null)

  const handleGenerate = async () => {
    setLoading(true)
    setError(null)
    const result = await fetchDailyRefinement(date, entries)
    saveRefinement(result.data)
    setRefinement(result.data)
    setSource(result.source)
    if (result.error) setError(result.error)
    onRefinementChange(result.data)
    setLoading(false)
  }

  const handleToggleChecklist = (itemId: string, completed: boolean) => {
    const updated = updateRefinementChecklist(date, itemId, completed)
    if (updated) {
      setRefinement(updated)
      onRefinementChange(updated)
    }
  }

  const handleClear = () => {
    deleteRefinement(date)
    setRefinement(undefined)
    onRefinementChange(undefined)
  }

  return (
    <section className="rounded-xl border border-indigo-200 bg-white p-5 shadow-sm">
      <div className="mb-4 flex flex-wrap items-center justify-between gap-2">
        <div className="flex items-center gap-2">
          <h2 className="text-lg font-semibold text-slate-800">AI 每日计划细化</h2>
          {refinement && (
            <span
              className={`rounded-full px-2 py-0.5 text-xs ${
                source === 'ai'
                  ? 'bg-indigo-100 text-indigo-700'
                  : 'bg-slate-100 text-slate-600'
              }`}
            >
              {source === 'ai' ? '大模型' : '本地规则'}
            </span>
          )}
        </div>
        <div className="flex gap-2">
          <button
            type="button"
            onClick={handleGenerate}
            disabled={loading}
            className="rounded-lg bg-indigo-600 px-4 py-2 text-sm font-medium text-white hover:bg-indigo-700 disabled:opacity-60"
          >
            {loading ? 'AI 生成中…' : refinement ? '重新生成' : '细化当天计划'}
          </button>
          {refinement && (
            <button
              type="button"
              onClick={handleClear}
              className="rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-600 hover:bg-slate-50"
            >
              清除
            </button>
          )}
        </div>
      </div>

      {!refinement && !loading && (
        <p className="text-sm text-slate-500">
          点击「细化当天计划」，系统将调用大模型 API 生成学习材料、具体练习和完成标准（未配置 API 时自动降级为本地模板）。
        </p>
      )}

      {loading && (
        <p className="animate-pulse text-sm text-indigo-600">正在调用 AI 分析当天任务并生成详细计划…</p>
      )}

      {error && source === 'local' && refinement && (
        <p className="mb-3 rounded-lg bg-amber-50 px-3 py-2 text-xs text-amber-800">
          AI 调用失败，已使用本地模板：{error}
        </p>
      )}

      {refinement && !loading && (
        <div className="space-y-4">
          <pre className="max-h-80 overflow-auto whitespace-pre-wrap rounded-lg bg-slate-50 p-4 font-sans text-sm leading-relaxed text-slate-700">
            {refinement.markdown}
          </pre>

          {refinement.checklist.length > 0 && (
            <div>
              <h3 className="mb-2 text-sm font-semibold text-slate-700">完成标准清单</h3>
              <ul className="space-y-2">
                {refinement.checklist.map((item) => (
                  <li key={item.id} className="flex items-start gap-2">
                    <input
                      type="checkbox"
                      checked={item.completed}
                      onChange={(e) => handleToggleChecklist(item.id, e.target.checked)}
                      className="mt-0.5 h-4 w-4 rounded border-slate-300 text-indigo-600"
                    />
                    <span
                      className={`text-sm ${
                        item.completed ? 'text-slate-400 line-through' : 'text-slate-700'
                      }`}
                    >
                      {item.text}
                    </span>
                  </li>
                ))}
              </ul>
            </div>
          )}

          <p className="text-xs text-slate-400">
            生成于 {new Date(refinement.generatedAt).toLocaleString('zh-CN')}
            {refinement.source === 'ai' ? ' · 由大模型生成' : ' · 本地模板生成'}
          </p>
        </div>
      )}
    </section>
  )
}

